1	export type Cell = [x: number, y: number];
2	
3	const cellKey = (x: number, y: number): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [ 0, -1],          [ 0, 1],
8	  [ 1, -1], [ 1, 0], [ 1, 1],
9	];
10	
11	export function nextGeneration(liveCells: Cell[]): Cell[] {
12	  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
13	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
14	
15	  for (const [x, y] of liveCells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const nx = x + dx;
18	      const ny = y + dy;
19	      const key = cellKey(nx, ny);
20	      const entry = neighborCounts.get(key);
21	      if (entry) entry.count += 1;
22	      else neighborCounts.set(key, { cell: [nx, ny], count: 1 });
23	    }
24	  }
25	
26	  const nextCells: Cell[] = [];
27	  for (const [key, { cell, count }] of neighborCounts) {
28	    const isAlive = liveSet.has(key);
29	    if ((isAlive && (count === 2 || count === 3)) || (!isAlive && count === 3)) {
30	      nextCells.push(cell);
31	    }
32	  }
33	  return nextCells;
34	}
35

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return an empty array when given an empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has 2 live neighbors (survival)", () => {
15	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
16	    expect(result).toContainEqual([0, 1]);
17	  });
18	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
19	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1], [2, 1]]);
20	    expect(result).not.toContainEqual([1, 1]);
21	  });
22	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
23	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
24	    expect(result).toContainEqual([1, 1]);
25	  });
26	  it("should preserve a block still-life pattern unchanged", () => {
27	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
28	    const result = nextGeneration(block);
29	    expect(result).toHaveLength(4);
30	    for (const cell of block) {
31	      expect(result).toContainEqual(cell);
32	    }
33	  });
34	  it.todo("should oscillate a vertical blinker to a horizontal blinker");
35	  it.todo("should handle negative coordinates correctly");
36	});
